import java.nio.ByteBuffer;
import java.nio.charset.StandardCharsets;
import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Use ByteBuffer with proper capacity
        ByteBuffer buffer = ByteBuffer.allocate(name.length());
        buffer.put(name.getBytes(StandardCharsets.UTF_8));

        System.out.println("Hello, " + new String(buffer.array(), StandardCharsets.UTF_8));
    }
}

### Explanation:
취약유형: Buffer Overflow
